<?php exec("systemctl list-unit-files --type=service --no-pager --no-legend", $services); $result = []; foreach ($services as $line) { $parts = preg_split('/\s+/', $line); if (count($parts) < 2) continue; $service = $parts[0]; exec("systemctl is-active $service", $statusOut); $status = trim($statusOut[0]); $result[] = [ 'name' => $service, 'status' => $status ]; } header('Content-Type: application/json'); echo json_encode($result, JSON_PRETTY_PRINT);
